}

/* ============================================================================
   DOGECOIN — lớp tiền tệ thống nhất (gộp Xu + Kim Cương).
   Nguồn: plugin PlayerPoints (nếu pp_enabled) hoặc cột mirror web_wallet.dogecoin.
   ========================================================================== */

/* UUID offline (md5 "OfflinePlayer:<tên>") — chuẩn server offline/cracked & PlayerPoints */
function offline_uuid($name){
  $h = md5('OfflinePlayer:'.$name, true);
  $h[6] = chr((ord($h[6]) & 0x0f) | 0x30);   // version 3
  $h[8] = chr((ord($h[8]) & 0x3f) | 0x80);   // variant
  $x = bin2hex($h);
  return substr($x,0,8).'-'.substr($x,8,4).'-'.substr($x,12,4).'-'.substr($x,16,4).'-'.substr($x,20,12);
}
/* UUID online (Mojang) — tra 1 lần rồi cache vào web_uuid */
function online_uuid($name){
  try{
    $st=db()->prepare("SELECT uuid FROM web_uuid WHERE username=? LIMIT 1"); $st->execute([strtolower($name)]);
    $r=$st->fetch(); if($r && $r['uuid']) return $r['uuid'];
  }catch(Exception $e){}
  $uuid=''; $url='https://api.mojang.com/users/profiles/minecraft/'.rawurlencode($name);
  $raw=@file_get_contents($url);
  if($raw){ $j=json_decode($raw,true);
    if(!empty($j['id']) && strlen($j['id'])===32){ $i=$j['id'];
      $uuid=substr($i,0,8).'-'.substr($i,8,4).'-'.substr($i,12,4).'-'.substr($i,16,4).'-'.substr($i,20,12);
    }
  }
  if($uuid==='') $uuid=offline_uuid($name); // fallback an toàn
  try{ db()->prepare("INSERT INTO web_uuid(username,uuid,created) VALUES(?,?,?) ON DUPLICATE KEY UPDATE uuid=VALUES(uuid)")->execute([strtolower($name),$uuid,ms()]); }catch(Exception $e){}
  return $uuid;
}
/* Khoá định danh người chơi trong PlayerPoints theo cấu hình */
function pp_key($name){
  global $CFG; $m=$CFG['uuid_mode']??'offline';
  if($m==='username') return $name;
  if($m==='online')   return online_uuid($name);
  return offline_uuid($name);
}
/* Đọc số dư Dogecoin */
function doge_balance($u){
  global $CFG;
  if(!empty($CFG['pp_enabled'])){
    try{ $key=pp_key($u);
      $st=db()->prepare("SELECT `{$CFG['pp_points_col']}` AS p FROM `{$CFG['pp_table']}` WHERE `{$CFG['pp_uuid_col']}`=? LIMIT 1");
      $st->execute([$key]); $r=$st->fetch(); return $r?(int)$r['p']:0;
    }catch(Exception $e){ /* rơi xuống mirror nếu lỗi */ }
  }
  try{ $st=db()->prepare("SELECT dogecoin FROM web_wallet WHERE username=? LIMIT 1"); $st->execute([$u]); $r=$st->fetch();
    if($r!==false) return (int)$r['dogecoin'];
    db()->prepare("INSERT INTO web_wallet(username,created) VALUES(?,?)")->execute([$u,ms()]); return 0;
  }catch(Exception $e){ return 0; }
}
/* Ghi đè số dư (dùng nội bộ) */
function doge_set($u,$amount){
  global $CFG; $amount=max(0,(int)$amount);
  if(!empty($CFG['pp_enabled'])){
    try{ $key=pp_key($u);
      db()->prepare("INSERT INTO `{$CFG['pp_table']}`(`{$CFG['pp_uuid_col']}`,`{$CFG['pp_points_col']}`) VALUES(?,?) ON DUPLICATE KEY UPDATE `{$CFG['pp_points_col']}`=VALUES(`{$CFG['pp_points_col']}`)")->execute([$key,$amount]);
    }catch(Exception $e){}
  }
  try{ db()->prepare("INSERT INTO web_wallet(username,dogecoin,created) VALUES(?,?,?) ON DUPLICATE KEY UPDATE dogecoin=VALUES(dogecoin)")->execute([$u,$amount,ms()]); }catch(Exception $e){}
}
/* Cộng Dogecoin — UPDATE delta atomic (không còn read-modify-write). */
function doge_add($u,$amt){
  global $CFG; $amt=(int)$amt; if($amt<=0) return true;
  if(!empty($CFG['pp_enabled'])){
    try{ $key=pp_key($u);
      db()->prepare("INSERT INTO `{$CFG['pp_table']}`(`{$CFG['pp_uuid_col']}`,`{$CFG['pp_points_col']}`) VALUES(?,?) ON DUPLICATE KEY UPDATE `{$CFG['pp_points_col']}`=`{$CFG['pp_points_col']}`+VALUES(`{$CFG['pp_points_col']}`)")->execute([$key,$amt]);
    }catch(Exception $e){}
  }
  try{ db()->prepare("INSERT INTO web_wallet(username,dogecoin,created) VALUES(?,?,?) ON DUPLICATE KEY UPDATE dogecoin=dogecoin+VALUES(dogecoin)")->execute([$u,$amt,ms()]); }catch(Exception $e){}
  return true;
}
/* Trừ Dogecoin — UPDATE có guard `dogecoin>=?`; chỉ thành công khi rowCount==1
   (ngăn over-draft khi 2 request chạy song song). $track=true cộng vào "đã tiêu" BXH. */
function doge_take($u,$amt,$track=true){
  global $CFG; $amt=(int)$amt; if($amt<=0) return true;
  $ok=false;
  if(!empty($CFG['pp_enabled'])){
    try{ $key=pp_key($u);
      $st=db()->prepare("UPDATE `{$CFG['pp_table']}` SET `{$CFG['pp_points_col']}`=`{$CFG['pp_points_col']}`-? WHERE `{$CFG['pp_uuid_col']}`=? AND `{$CFG['pp_points_col']}`>=?");
      $st->execute([$amt,$key,$amt]);
      $ok = $st->rowCount()===1;
    }catch(Exception $e){ return false; }
  } else {
    try{
      db()->prepare("INSERT IGNORE INTO web_wallet(username,created) VALUES(?,?)")->execute([$u,ms()]);
      $st=db()->prepare("UPDATE web_wallet SET dogecoin=dogecoin-? WHERE username=? AND dogecoin>=?");
      $st->execute([$amt,$u,$amt]);
      $ok = $st->rowCount()===1;
    }catch(Exception $e){ return false; }
  }
  if(!$ok) return false;
  if($track){ try{ db()->prepare("INSERT INTO web_wallet(username,doge_spent,created) VALUES(?,?,?) ON DUPLICATE KEY UPDATE doge_spent=doge_spent+VALUES(doge_spent)")->execute([$u,$amt,ms()]); }catch(Exception $e){} }
  return true;
}
/* Định dạng hiển thị Dogecoin */
function doge_fmt($n){ global $CFG; return number_format((int)$n,0,',','.').' '.($CFG['doge_label']??'Dogecoin'); }
function doge_short($n){ global $CFG; return ($CFG['doge_symbol']??'Ð').number_format((int)$n,0,',','.'); }
/* Chuẩn hoá mã item: "Diamond Sword" -> "diamond_sword" */
function ikey_norm($s){ $s=strtolower(trim((string)$s)); $s=preg_replace('/[\s\-]+/','_',$s); return preg_replace('/[^a-z0-9_]/','', $s); }
/* URL icon vật phẩm từ API (mã item dạng diamond_sword) */
function item_icon($key){
  global $CFG; $key=strtolower(trim((string)$key));
  $key=preg_replace('/[\s\-]+/','_',$key);          // "Diamond Sword" -> "diamond_sword"
  $key=preg_replace('/[^a-z0-9_]/','', $key);
  if($key==='') return '?img=doge';
  return sprintf($CFG['item_icon_api'], rawurlencode($key));
}
/* Ảnh hiển thị cho 1 vật phẩm: ưu tiên ảnh tuỳ chỉnh, nếu trống thì lấy icon từ API theo mã item */
function item_img($image,$key=''){ $image=trim((string)$image); return $image!=='' ? $image : item_icon($key); }
/* Tải ảnh vật phẩm lên (field=image_file). Trả URL tương đối, hoặc '' nếu không có/không hợp lệ. */
function item_upload($field='image_file'){
  global $CFG;
  if(empty($_FILES[$field]) || ($_FILES[$field]['error']??UPLOAD_ERR_NO_FILE)!==UPLOAD_ERR_OK) return '';
  $f=$_FILES[$field]; $ext=strtolower(pathinfo($f['name'],PATHINFO_EXTENSION));
  $ok=$CFG['upload_image_ext']??['jpg','jpeg','png','gif','webp','avif','bmp'];
  if(!in_array($ext,$ok,true)) return '';
  if($f['size'] > (int)($CFG['upload_max_mb']??25)*1048576) return '';
  $dir=__DIR__.'/uploads/items'; $url='uploads/items';
  if(!is_dir($dir)) @mkdir($dir,0775,true);
  $name='it_'.bin2hex(random_bytes(8)).'.'.$ext;
  if(@move_uploaded_file($f['tmp_name'],$dir.'/'.$name)) return $url.'/'.$name;
  return '';
}

/* Kết toán các phiên đấu giá đã hết giờ (gọi lười khi tải trang Đấu Giá / khi đặt giá).
   - Có người đấu  → bán: người bán nhận giá chốt, vật phẩm vào kho người thắng (+RCON nếu cần).
   - Không ai đấu  → hết hạn: HOÀN phí mở; nếu lấy từ kho thì TRẢ vật phẩm về kho người bán. */
function auc_settle_due(){
  try{
    $now=ms();
    $due=db()->query("SELECT * FROM web_auctions WHERE status='active' AND end_at<=$now")->fetchAll();
    foreach($due as $a){
      $qty=max(1,(int)($a['qty']??1));
      $sold = $a['top_bidder']!=='';
      // Claim trước: chỉ request nào thực sự lật status='active'→'sold|expired'
      // mới được trả tiền / phát vật phẩm. Hai page-load song song sẽ chỉ có 1
      // rowCount==1, tránh trả thưởng & spawn item 2 lần.
      $claim = db()->prepare("UPDATE web_auctions SET status=? WHERE id=? AND status='active'");
      $claim->execute([$sold?'sold':'expired', $a['id']]);
      if($claim->rowCount()!==1) continue;
      if($sold){
        doge_add($a['seller'],(int)$a['price']);
        db()->prepare("INSERT INTO web_inventory(username,mode,item,item_key,qty,color,image) VALUES(?,?,?,?,?, '#f2b631', ?)")
            ->execute([$a['top_bidder'],$a['mode']??'',$a['item'],$a['item_key'],$qty,$a['image']??'']);
        $gw=rcon_arg($a['top_bidder'],32); $gk=rcon_arg($a['item_key'],48);
        if($gw!=='' && $gk!=='') rcon_queue('give '.$gw.' minecraft:'.$gk.' '.(int)$qty, 'AUCTION');
        notify($a['top_bidder'],'gift','Bạn đã thắng đấu giá 🏆','"'.$a['item'].'" với '.doge_short((int)$a['price']).' — đã vào kho của bạn.','?p=auction','SYSTEM');
        notify($a['seller'],'gift','Phiên đấu giá đã bán 💰','"'.$a['item'].'" bán cho '.$a['top_bidder'].' (+'.doge_short((int)$a['price']).').','?p=auction','SYSTEM');
      } else {
        doge_add($a['seller'],(int)$a['listing_fee']); // hoàn phí mở
        if(!empty($a['from_inv'])){ // trả vật phẩm về kho người bán
          db()->prepare("INSERT INTO web_inventory(username,mode,item,item_key,qty,color,image) VALUES(?,?,?,?,?, '#f2b631', ?)")
              ->execute([$a['seller'],$a['mode']??'',$a['item'],$a['item_key'],$qty,$a['image']??'']);
        }
        notify($a['seller'],'info','Phiên đấu giá hết hạn','"'.$a['item'].'" không có ai đấu — đã hoàn phí mở'.(!empty($a['from_inv'])?' và trả vật phẩm về kho':'').'.','?p=auction','SYSTEM');
      }
    }
  }catch(Exception $e){}
}

/* --- DB (kết nối lười: chỉ khi cần) --- */
/* ============================================================================
   HELPERS MỞ RỘNG — thông báo, giá nạp động, chat admin, gift code, mention
   ========================================================================== */
/* Tạo 1 thông báo cho 1 người (hiện ở chuông) */
function notify($to,$type,$title,$body='',$link='',$actor=''){
  if(!$to) return;
  try{ db()->prepare("INSERT INTO web_notifications(username,type,title,body,link,actor,created) VALUES(?,?,?,?,?,?,?)")
        ->execute([$to,$type,mb_substr_safe($title,0,190),mb_substr_safe($body,0,255),$link,$actor,ms()]); }catch(Exception $e){}
}
/* Danh sách tên tất cả admin (gồm owner) */
function dgl_admin_names(){
  global $CFG; $names=[]; if(!empty($CFG['owner'])) $names[strtolower($CFG['owner'])]=$CFG['owner'];
  try{ foreach(db()->query("SELECT username FROM web_admins")->fetchAll(PDO::FETCH_COLUMN) as $a) $names[strtolower($a)]=$a; }catch(Exception $e){}
  foreach(($CFG['admins']??[]) as $a) $names[strtolower($a)]=$a;
  return array_values($names);
}
/* Thông báo cho mọi admin (trừ $except) */
function notify_admins($type,$title,$body='',$link='',$actor='',$except=''){
  foreach(dgl_admin_names() as $a){ if($except!=='' && strtolower($a)===strtolower($except)) continue; notify($a,$type,$title,$body,$link,$actor); }
}
/* Lấy / lưu cấu hình động (web_settings) */
function dgl_setting($k,$def=null){
  static $cache=null;
  if($cache===null){ $cache=[]; try{ foreach(db()->query("SELECT k,v FROM web_settings")->fetchAll() as $r) $cache[$r['k']]=$r['v']; }catch(Exception $e){} }
  return array_key_exists($k,$cache) ? $cache[$k] : $def;
}
function dgl_set_setting($k,$v){ try{ db()->prepare("INSERT INTO web_settings(k,v) VALUES(?,?) ON DUPLICATE KEY UPDATE v=VALUES(v)")->execute([$k,(string)$v]); }catch(Exception $e){} }
/* Thông tin khuyến mãi đang áp dụng */
function dgl_promo(){
  $pc=(int)dgl_setting('promo_percent',0); $until=dgl_setting('promo_until','');
  $until=$until!==''?(int)$until:0; $active = $pc>0 && ($until===0 || $until>ms());
  return ['percent'=>$pc,'until'=>$until,'active'=>$active];
}
/* Cộng % thưởng khuyến mãi vào số Kim Cương */
function apply_promo_dia($dia){ $p=dgl_promo(); return $p['active'] ? (int)round($dia*(1+$p['percent']/100)) : (int)$dia; }
/* Nạp đè $PACKAGES + tỉ giá từ DB (cho phép admin chỉnh giá) */
function dgl_apply_pricing(){
  global $PACKAGES,$CFG;
  try{
    $rows=db()->query("SELECT * FROM web_packages ORDER BY sort,id")->fetchAll();
    if($rows){ $PACKAGES=[]; foreach($rows as $r){ $PACKAGES[]=['amount'=>(int)$r['amount'],'dia'=>(int)$r['dia'],'xu'=>(int)$r['xu'],'bonus'=>$r['bonus'],'hot'=>!empty($r['hot'])]; } }
  }catch(Exception $e){}
  $map=['vnd_per_diamond'=>'int','custom_min'=>'int','custom_max'=>'int'];
  foreach($map as $k=>$t){ $v=dgl_setting($k,null); if($v!==null && $v!=='') $CFG[$k]=(int)$v; }
}
/* Chat nội bộ admin */
function chat_sys($msg){ try{ db()->prepare("INSERT INTO web_chat(username,message,kind,created) VALUES('SYSTEM',?,?,?)")->execute([$msg, 'system', ms()]); }catch(Exception $e){} }
function chat_send($u,$msg){ try{ db()->prepare("INSERT INTO web_chat(username,message,kind,created) VALUES(?,?, 'msg', ?)")->execute([$u,$msg,ms()]); return (int)db()->lastInsertId(); }catch(Exception $e){ return 0; } }
/* Quét ticket tồn đọng (>=2 ngày chưa đóng) → báo vào chat admin (giới hạn 5 phút/lần) */
function chat_check_stale_tickets(){
  $last=(int)dgl_setting('chat_stale_check',0); $now=ms();
  if($now-$last < 300000) return; dgl_set_setting('chat_stale_check',$now);
  try{
    $cut=$now-2*86400000;
    $rows=db()->query("SELECT id,code,subject,username,updated FROM web_tickets WHERE status<>'closed' AND chat_alert=0 AND updated<$cut ORDER BY updated ASC LIMIT 20")->fetchAll();
    foreach($rows as $t){
      $code=$t['code']?:ticket_code($t['id']);
      $days=floor(($now-(int)$t['updated'])/86400000);
      chat_sys('⏳ Ticket '.$code.' ("'.mb_substr_safe($t['subject'],0,60).'") của '.$t['username'].' đã '.$days.' ngày chưa được xử lý.');
      db()->prepare("UPDATE web_tickets SET chat_alert=1 WHERE id=?")->execute([$t['id']]);
      notify_admins('ticket','Ticket tồn đọng '.$code,$days.' ngày chưa xử lý','?p=ticket&id='.(int)$t['id'],'SYSTEM');
    }
  }catch(Exception $e){}
}
/* Kiểm tra CSRF cho request AJAX (token gửi qua POST hoặc header) */
function ajax_csrf_ok(){
  $t=$_POST['csrf']??($_SERVER['HTTP_X_CSRF']??'');
  return isset($_SESSION['csrf']) && $t!=='' && hash_equals($_SESSION['csrf'],$t);
}
function json_out($a){ header('Content-Type: application/json; charset=utf-8'); echo json_encode($a, JSON_UNESCAPED_UNICODE); exit; }
/* Tài khoản tồn tại trong AuthMe? (dùng cho @mention) */
function user_exists($name){
  global $CFG; if(!$name) return false;
  try{ $st=db()->prepare("SELECT realname FROM `".$CFG['authme_table']."` WHERE LOWER(username)=? LIMIT 1"); $st->execute([strtolower($name)]); $r=$st->fetch(); return $r?($r['realname']?:$name):false; }catch(Exception $e){ return false; }
}
/* Trích các @mention hợp lệ từ nội dung (trả về realname chuẩn) */
function parse_mentions($text){
  if(!preg_match_all('/@([A-Za-z0-9_]{3,16})/u',$text,$m)) return [];
  $out=[]; foreach(array_unique($m[1]) as $nm){ $rn=user_exists($nm); if($rn) $out[strtolower($rn)]=$rn; }
  return array_values($out);
}

